function SettingsModal() {

  const [display, toggleDisplay] = useState(true);

  const toddleModal = () => {
    toggleDisplay(n => !n)
  };

  return (
    <div className="modal-container">
      <div className="modal">
        <button onClick={ () => { toddleModal(); }}> show Modal </button>
      </div>
    </div>
  );
}

export default SettingsModal;
